import * as React from 'react';
import { styled } from '@mui/material/styles';
import Switch from '@mui/material/Switch';
import FormControlLabel from '@mui/material/FormControlLabel';

// Custom Styled Switch
const CustomSwitch = styled(Switch)(({ theme }) => ({
  width: 62,
  height: 34,
  padding: 7,
  '& .MuiSwitch-switchBase': {
    margin: 1,
    padding: 0,
    transform: 'translateX(6px)',
    '&.Mui-checked': {
      color: '#fff',
      transform: 'translateX(22px)',
      '& + .MuiSwitch-track': {
        backgroundColor: '#19B373', // Success green background
        opacity: 1,
        border: 'none',
      },
      '& .MuiSwitch-thumb': {
        backgroundColor: '#19B373', // Success green thumb (circle)
      },
    },
  },
  '& .MuiSwitch-thumb': {
    backgroundColor: '#666666', // Danger red thumb (circle)
    width: 32,
    height: 32,
  },
  '& .MuiSwitch-track': {
    borderRadius: 20 / 2,
    backgroundColor: '#999999', // Danger red background
    opacity: 1,
  },
}));

export default function Toggle() {
  const [checked, setChecked] = React.useState(false);

  const handleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setChecked(event.target.checked);
  };

  return (
    <FormControlLabel
      control={
        <CustomSwitch
          checked={checked}
          onChange={handleChange}
          inputProps={{ 'aria-label': 'controlled' }}
        />
      }
      label={checked ? 'Dark mode' : 'Light mode'}
    />
  );
}
